// ==== CONFIG: edit these to match your Notion database ====
const DUE_PROPERTY    = 'Due';      // Date property that holds the deadline
const STATUS_PROPERTY = 'Status';   // Status or Select property that holds task state
const DONE_VALUES     = ['Done', 'Complete', 'Completed', 'Cancelled', 'Archived']; // states treated as finished, never rolled
const ROLLED_PROPERTY = 'Rolled';   // Number property: how many times this task has been rolled
const STALE_PROPERTY  = 'Stale';    // Checkbox property: set true once a task is rolled past the threshold
const STALE_THRESHOLD = 3;          // flag Stale once a task has been rolled MORE than this many times
const ROLL_TO         = 'today';    // 'today' | 'nextBusinessDay'
// ==========================================================

// "Today" comes from n8n's $now (a Luxon DateTime), taken at calendar-date granularity.
const todayISO = $now.toISODate(); // 'yyyy-MM-dd'

const doneSet = new Set(DONE_VALUES.map((v) => String(v).trim().toLowerCase()));

function propOf(page, name) {
  return ((page && page.properties) || {})[name];
}

function readDueDate(page) {
  const p = propOf(page, DUE_PROPERTY);
  if (!p) return '';
  if (p.type === 'date' && p.date && p.date.start) return String(p.date.start);
  if (p.type === 'formula' && p.formula && p.formula.date && p.formula.date.start) return String(p.formula.date.start);
  return '';
}

function readStatus(page) {
  const p = propOf(page, STATUS_PROPERTY);
  if (!p) return '';
  if (p.type === 'status') return (p.status && p.status.name) || '';
  if (p.type === 'select') return (p.select && p.select.name) || '';
  return '';
}

function readRolled(page) {
  const p = propOf(page, ROLLED_PROPERTY);
  if (p && p.type === 'number' && p.number != null) return Number(p.number);
  return 0;
}

function readTitle(page) {
  const props = (page && page.properties) || {};
  for (const k of Object.keys(props)) {
    if (props[k] && props[k].type === 'title') {
      return (props[k].title || []).map((x) => x.plain_text).join('');
    }
  }
  return '';
}

function nextBusinessDay(iso) {
  // Snap a weekend date up to Monday. Weekday dates are returned unchanged.
  const d = new Date(iso + 'T00:00:00Z');
  let dow = d.getUTCDay(); // 0 = Sunday, 6 = Saturday
  while (dow === 0 || dow === 6) {
    d.setUTCDate(d.getUTCDate() + 1);
    dow = d.getUTCDay();
  }
  return d.toISOString().slice(0, 10);
}

const rollTargetISO = ROLL_TO === 'nextBusinessDay' ? nextBusinessDay(todayISO) : todayISO;

const out = [];
for (const item of items) {
  const page = item.json;

  const dueStart = readDueDate(page);
  if (!dueStart) continue;                 // no due date, nothing to roll
  const dueDateOnly = dueStart.slice(0, 10);
  if (dueDateOnly >= todayISO) continue;    // due today or in the future, not overdue

  const status = readStatus(page);
  if (doneSet.has(status.trim().toLowerCase())) continue; // finished tasks are never touched

  if (rollTargetISO === dueDateOnly) continue; // no-op guard: skip if the date would not change

  const newRolled = readRolled(page) + 1;
  const stale = newRolled > STALE_THRESHOLD;

  out.push({
    json: {
      pageId: page.id,
      taskName: readTitle(page),
      statusValue: status,
      oldDue: dueDateOnly,
      newDate: rollTargetISO,
      newRolled: newRolled,
      stale: stale,
    },
  });
}

return out;
